// ─────────────────────────────────────────────
//  components/PostForm.js
//  Form to write and submit a new blog post
// ─────────────────────────────────────────────
import React, { useState } from 'react';
import { createPost } from '../api';

const PostForm = ({ onPostCreated }) => {
  // Local state for the two form fields
  const [title,   setTitle]   = useState('');
  const [content, setContent] = useState('');
  const [loading, setLoading] = useState(false);
  const [error,   setError]   = useState('');

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');

    // Simple client-side validation
    if (!title.trim() || !content.trim()) {
      setError('Both title and content are required.');
      return;
    }

    try {
      setLoading(true);
      await createPost({ title: title.trim(), content: content.trim() });

      // Clear the form on success
      setTitle('');
      setContent('');

      // Tell the parent (App.js) to refresh the post list
      onPostCreated();
    } catch (err) {
      setError(err.response?.data?.message || 'Something went wrong. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <section className="form-section">
      <h2 className="section-title">
        <span className="title-accent">✦</span> Write a Post
      </h2>

      {error && <p className="error-msg">{error}</p>}

      <form onSubmit={handleSubmit} className="post-form">
        <div className="form-group">
          <label htmlFor="title">Title</label>
          <input
            id="title"
            type="text"
            placeholder="Give your post a compelling title…"
            value={title}
            onChange={(e) => setTitle(e.target.value)}
            disabled={loading}
          />
        </div>

        <div className="form-group">
          <label htmlFor="content">Content</label>
          <textarea
            id="content"
            rows={6}
            placeholder="Start writing your thoughts here…"
            value={content}
            onChange={(e) => setContent(e.target.value)}
            disabled={loading}
          />
        </div>

        <button type="submit" className="submit-btn" disabled={loading}>
          {loading ? 'Publishing…' : 'Publish Post →'}
        </button>
      </form>
    </section>
  );
};

export default PostForm;
